form:Form.form:Scripts:
		function ValidarGrilla(){
	var bolResult = true;
	var objGrid = Ctrl("grdUniformes");
	var totalRows = objGrid.TotalRowsCount();
	var i;
	var colDevuelve;
	var colMotivoDevolucion;

	for(i = 0; i < totalRows; i++){
		colDevuelve = objGrid.GetCellXValue("e_devuelve",i);	
		if(colDevuelve > 0 ){
			colPendiente = objGrid.GetCellXValue("e_pendiente",i);
			if(colPendiente < colDevuelve){
				bolResult = false;
				objTextBox = objGrid.GetCellControl("e_devuelve",i);
				objTextBox.SetFocus();	
				alert("La cantidad devuelta no puede ser mayor a la pendiente");
				objGrid.SetCellXValue("e_devuelve",i,"");
				break;
			}
			colMotivoDevolucion = objGrid.GetCellXValue("oi_mot_devolucion",i);
			if(colMotivoDevolucion == null || colMotivoDevolucion == ""){
				bolResult = false;
				objTextBox = objGrid.GetCellControl("oi_mot_devolucion",i);
				objTextBox.SetFocus();	
				alert("Debe establecer un motivo de devolución");
				break;
			}
		}else if(colDevuelve < 0 ){
				bolResult = false;
				objTextBox = objGrid.GetCellControl("e_devuelve",i);
				objTextBox.SetFocus();
				alert("El valor devuelto tiene que ser mayor a 0");
				objGrid.SetCellXValue("e_devuelve",i,"");
				//objGrid.SetCellSelectedXValue("e_devuelve","");
				break;
			}
	}

	if(bolResult)
		Ctrl("main").DoEvent("EXECUTE");
}
